    def capture(r, c):
        if r < 0 or c < 0 or r >= ROWS or c >= COLS or board[r][c] != 'O':
            return
        board[r][c] = 'T'
        capture(r + 1, c)
        capture(r - 1, c)
        capture(r, c + 1)
        capture(r, c - 1)
    for r in range(ROWS):
        for c in range(COLS):
            if (r == 0 or r == ROWS - 1 or c == 0 or c == COLS - 1) and board[r][c] == 'O':
